export const QUESTIONS = [{"id":"5yAGChiafx6OxygHJHZC","type":"objective","question":"The governor's speech was rather verbose, leaving the audience confused about his actual plans.","options":["concise","wordy","inspiring","ambiguous"],"answerIndex":1,"answer":null,"explanation":"The word 'verbose' means using more words than needed, which is synonymous with 'wordy'.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"utme","subject":"english","subjectLabel":"English Language","grade":"Unsorted"},{"id":"CSySW4aVv7xAkg4HSQ82","type":"objective","question":"Neither the principal nor the teachers _______ present at the emergency meeting yesterday.","options":["was","were","is","are"],"answerIndex":1,"answer":null,"explanation":"When subjects are joined by 'neither... nor', the verb agrees in number with the nearer subject, which is the plural noun 'teachers'.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"utme","subject":"english","subjectLabel":"English Language","grade":"Unsorted"},{"id":"I0y3DyuqLKaR2zYi6M6B","type":"objective","question":"Choose the word that has the same vowel sound as the underlined letter in the word: b<u>u</u>ry","options":["fury","berry","jury","dirty"],"answerIndex":1,"answer":null,"explanation":"The word 'bury' is pronounced with the short /e/ sound, matching the vowel sound in 'berry'.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"utme","subject":"english","subjectLabel":"English Language","grade":"Unsorted"},{"id":"VY1dVTSeFLVX6HyXnz6C","type":"objective","question":"The board recommended that the managing director _______ with immediate effect.","options":["resigns","resign","should resign","resigned"],"answerIndex":1,"answer":null,"explanation":"The subjunctive mood, used after verbs of recommendation or demand, requires the base form of the verb ('resign').","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"utme","subject":"english","subjectLabel":"English Language","grade":"Unsorted"},{"id":"WqHnJdcMEl4Ewz2r9Jyq","type":"objective","question":"Unlike his twin brother who is extremely frugal, Chidi spends money without a second thought.","options":["generous","miserly","extravagant","prudent"],"answerIndex":2,"answer":null,"explanation":"The opposite of 'frugal' (sparing or economical) is 'extravagant' (spending money excessively).","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"utme","subject":"english","subjectLabel":"English Language","grade":"Unsorted"},{"id":"YvB6MMLhDkX5SQpIOABk","type":"objective","question":"Between you and _______, I do not think the new policy will succeed.","options":["I","me","myself","we"],"answerIndex":1,"answer":null,"explanation":"The preposition 'between' must be followed by pronouns in the objective case, making 'me' the correct choice.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"utme","subject":"english","subjectLabel":"English Language","grade":"Unsorted"},{"id":"d1x96AIB46xUU5JQft9X","type":"objective","question":"The management has decided to comply _______ the new safety regulations issued by the federal government.","options":["with","to","by","at"],"answerIndex":0,"answer":null,"explanation":"The verb 'comply' is grammatically followed by the preposition 'with'.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"utme","subject":"english","subjectLabel":"English Language","grade":"Unsorted"},{"id":"kdbcJCWXACtMuFaCy4VS","type":"objective","question":"If I had known about the traffic, I would have taken the bypass. This means that the speaker:","options":["took the bypass because they knew about the traffic","did not take the bypass because they did not know about the traffic","knew about the traffic but chose not to take the bypass","took the bypass without knowing about the traffic"],"answerIndex":1,"answer":null,"explanation":"This third conditional sentence implies that the speaker did not know about the traffic and therefore did not take the bypass.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"utme","subject":"english","subjectLabel":"English Language","grade":"Unsorted"},{"id":"ndfPeqp6OaXschoGRGfW","type":"objective","question":"Which of the following syllables carries the primary stress in the word 'photographer'?","options":["first","second","third","fourth"],"answerIndex":1,"answer":null,"explanation":"The primary stress in 'photographer' falls on the second syllable (pho-TOG-ra-pher).","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"utme","subject":"english","subjectLabel":"English Language","grade":"Unsorted"},{"id":"oLfk7ZfsPzru7taVuJEj","type":"objective","question":"The police _______ still investigating the cause of the mysterious fire outbreak.","options":["is","are","was","has been"],"answerIndex":1,"answer":null,"explanation":"The noun 'police' is a collective noun that is plural in construction and always takes a plural verb.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"utme","subject":"english","subjectLabel":"English Language","grade":"Unsorted"},{"id":"p48GaeaKAexY5lw10If5","type":"objective","question":"Choose the word that has the same consonant sound as the underlined letters in: la<u>ugh</u>","options":["ghost","dough","rough","plough"],"answerIndex":2,"answer":null,"explanation":"The letters 'gh' in both 'laugh' and 'rough' are pronounced as the voiceless labiodental fricative /f/.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"utme","subject":"english","subjectLabel":"English Language","grade":"Unsorted"},{"id":"pHDKuyO73VFEBgaabTWb","type":"objective","question":"Choose the question to which the given sentence is the appropriate answer. Sentence: 'My mother bought a RED car yesterday.' (with emphasis on 'RED')","options":["Did your mother buy a red car yesterday?","Did your mother buy a blue car yesterday?","Did your father buy a red car yesterday?","Did your mother sell a red car yesterday?"],"answerIndex":1,"answer":null,"explanation":"Emphatic stress on the word 'RED' indicates that the color is the piece of information being corrected or contrasted, making 'blue' the appropriate point of contrast in the question.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"utme","subject":"english","subjectLabel":"English Language","grade":"Unsorted"},{"id":"qR3sA9v06qIGUPbC6408","type":"objective","question":"She rarely goes to the market these days, _______?","options":["doesn't she","does she","isn't it","is she"],"answerIndex":1,"answer":null,"explanation":"Since 'rarely' has a negative connotation, it requires a positive question tag, which is 'does she'.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"utme","subject":"english","subjectLabel":"English Language","grade":"Unsorted"},{"id":"qwZWEkUmDH71JEWzveeD","type":"objective","question":"After months of heated arguments, the two business partners finally decided to bury the hatchet.","options":["disown each other","make peace","hide their weapons","liquidate the company"],"answerIndex":1,"answer":null,"explanation":"To 'bury the hatchet' is an idiomatic expression that means to make peace or end a conflict.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"utme","subject":"english","subjectLabel":"English Language","grade":"Unsorted"},{"id":"rkWw9cv6bEpnpyKP0yAj","type":"objective","question":"The judge dismissed the case because the evidence presented by the prosecutor was not _______.","options":["admissible","permissible","acceptable","accessible"],"answerIndex":0,"answer":null,"explanation":"In legal terminology, evidence that is allowed to be introduced in court is described as 'admissible'.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"utme","subject":"english","subjectLabel":"English Language","grade":"Unsorted"},{"id":"7Rv2c1dT1J7eRo9DJdaD","type":"objective","question":"Choose the option that best explains the information conveyed in the sentence: \\textit{If I had known about the lecture, I would have attended it.}","options":["The speaker knew about the lecture and attended it.","The speaker did not know about the lecture and did not attend it.","The speaker knew about the lecture but did not attend it.","The speaker did not know about the lecture but attended it."],"answerIndex":1,"answer":null,"explanation":"The sentence uses the third conditional (if + past perfect, would have + past participle) to describe a counterfactual past situation. It implies the speaker did not know about the lecture, and consequently, did not attend it.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"utme","subject":"english","subjectLabel":"English Language","grade":"Unsorted"},{"id":"JZqYW5kCaupErXp2cBVy","type":"objective","question":"Choose the option nearest in meaning to the bold word: The politician's \\textbf{mercurial} temperament made it difficult for his aides to predict his reactions.","options":["phlegmatic","volatile","somber","steadfast"],"answerIndex":1,"answer":null,"explanation":"'Mercurial' means subject to sudden or unpredictable changes of mood or mind, which is synonymous with 'volatile'.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"utme","subject":"english","subjectLabel":"English Language","grade":"Unsorted"},{"id":"OegNdkReK7vczUx2zJ3L","type":"objective","question":"Choose the word that has the correct stress pattern for the word: \\textbf{reputable}.","options":["REputable","rePUTable","repuTAble","reputaBLE"],"answerIndex":0,"answer":null,"explanation":"The word 'reputable' is a four-syllable word stressed on the first syllable: \\(/\\textit{ˈrep.jə.tə.bəl}/\\), represented as REputable.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"utme","subject":"english","subjectLabel":"English Language","grade":"Unsorted"},{"id":"QveoV479twhoNTxFJy71","type":"objective","question":"Choose the option opposite in meaning to the bold word: In sharp contrast to her sister's \\textbf{garrulous} nature, Amina was known to be quiet and reserved.","options":["loquacious","taciturn","gregarious","vociferous"],"answerIndex":1,"answer":null,"explanation":"'Garrulous' means excessively talkative, especially on trivial matters. Its opposite is 'taciturn', which means reserved or uncommunicative in speech.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"utme","subject":"english","subjectLabel":"English Language","grade":"Unsorted"},{"id":"UOtxlkAMfyaqJ4vP96dG","type":"objective","question":"The newly appointed manager decided to \\textit{_______} the controversial policy introduced by his predecessor.","options":["phase out","phase off","phase down","phase through"],"answerIndex":0,"answer":null,"explanation":"'Phase out' is a phrasal verb meaning to gradually stop using or doing something over a period of time.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"utme","subject":"english","subjectLabel":"English Language","grade":"Unsorted"},{"id":"VVcE8cGWdqZalMU6NJjb","type":"objective","question":"Neither the principal nor the teachers \\textit{_______} present at the emergency meeting yesterday.","options":["was","were","are","is"],"answerIndex":1,"answer":null,"explanation":"According to the rule of proximity in concord, when subject nouns are joined by 'neither... nor', the verb agrees in number with the subject closer to it. 'Teachers' is plural and close to the verb, and the tense is past ('yesterday'), so 'were' is correct.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"utme","subject":"english","subjectLabel":"English Language","grade":"Unsorted"},{"id":"WwYfgX09BbhkOH3xra3E","type":"objective","question":"Choose the option that has the same consonant sound as the one represented by the underlined letter(s) in the word: vi\\underline{si}on.","options":["pleasure","pressure","nation","church"],"answerIndex":0,"answer":null,"explanation":"The 'si' in 'vision' is pronounced as the voiced postalveolar fricative \\(/ʒ/\\). This sound is also present in 'pleasure'. 'Pressure' and 'nation' have the voiceless \\(/ʃ/\\) sound, while 'church' has the affricate \\(/tʃ/\\).","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"utme","subject":"english","subjectLabel":"English Language","grade":"Unsorted"},{"id":"e8vJnZojPzbsgO6rqtt3","type":"objective","question":"Choose the option that has the same vowel sound as the one represented by the underlined letter(s) in the word: f\\underline{oo}t.","options":["boot","could","blood","route"],"answerIndex":1,"answer":null,"explanation":"The word 'foot' contains the short vowel sound \\(/ʊ/\\). 'Could' also contains the short \\(/ʊ/\\) sound, whereas 'boot' and 'route' contain \\(/uː/\\), and 'blood' contains \\(/ʌ/\\).","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"utme","subject":"english","subjectLabel":"English Language","grade":"Unsorted"},{"id":"hK0ykhXpi4QIGRmYmmKv","type":"objective","question":"It is high time we \\textit{_______} the truth about the missing funds.","options":["tell","told","should tell","had told"],"answerIndex":1,"answer":null,"explanation":"The subjunctive construction 'it is high time' is followed by a past subjunctive verb form ('told') to express a present or future action that is overdue.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"utme","subject":"english","subjectLabel":"English Language","grade":"Unsorted"},{"id":"v5iusdir9VMtJ1IpUGgs","type":"objective","question":"The host presented the winner with a \\textit{_______} trophy.","options":["beautiful silver Nigerian","Nigerian beautiful silver","beautiful Nigerian silver","silver beautiful Nigerian"],"answerIndex":2,"answer":null,"explanation":"Adjective ordering in English follows the general pattern: Opinion (beautiful) + Origin (Nigerian) + Material (silver). Thus, 'beautiful Nigerian silver' is the correct sequence.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"utme","subject":"english","subjectLabel":"English Language","grade":"Unsorted"},{"id":"1jYH8CkcyjkaqDSIgYkB","type":"objective","question":"Neither the principal nor the teachers _______ present at the emergency meeting yesterday.","options":["was","were","are","is"],"answerIndex":1,"answer":null,"explanation":"In a 'neither... nor...' structure, the verb agrees in number with the nearer subject.,Since 'teachers' is plural and the time marker is 'yesterday' (past tense), the plural past verb 'were' is correct.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"utme","subject":"english","subjectLabel":"English Language","grade":"Unsorted"},{"id":"BgExAEXiVZI7bh26epxh","type":"objective","question":"The suspect was acquitted _______ the charges of armed robbery due to a lack of evidence.","options":["from","of","with","for"],"answerIndex":1,"answer":null,"explanation":"The verb 'acquitted' is idiomatically paired with the preposition 'of' when referring to charges.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"utme","subject":"english","subjectLabel":"English Language","grade":"Unsorted"},{"id":"GgGmHQ9C6RXusNKRURjX","type":"objective","question":"Choose the option to which the given sentence is the appropriate answer.\\n\\nMy mother bought a BLUE dress for the wedding.","options":["Did your sister buy a blue dress for the wedding?","Did your mother sew a blue dress for the wedding?","Did your mother buy a red dress for the wedding?","Did your mother buy a blue skirt for the wedding?"],"answerIndex":2,"answer":null,"explanation":"Emphatic stress on 'BLUE' means that the word 'blue' contains the new or corrective information.,The correct question must contradict this stressed word, which is 'red' in the correct option.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"utme","subject":"english","subjectLabel":"English Language","grade":"Unsorted"},{"id":"MNYywVyX7v2WGgO0UIso","type":"objective","question":"You hardly ever attend these weekend seminars, _______?","options":["don't you","do you","hardly you","isn't it"],"answerIndex":1,"answer":null,"explanation":"'Hardly' is a negative adverb, which makes the statement semantically negative.,A negative statement requires a positive question tag, which is 'do you?'.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"utme","subject":"english","subjectLabel":"English Language","grade":"Unsorted"},{"id":"N0cXyzAYRRjunQk62cFT","type":"objective","question":"Choose the option that best explains the meaning of the bolded idiom:\\n\\nWhen the news of his suspension broke, the commissioner decided to **take the bull by the horns**.","options":["run away from the situation","confront the difficult situation head-on","blame his subordinates for the problem","seek political asylum abroad"],"answerIndex":1,"answer":null,"explanation":"To 'take the bull by the horns' is an idiomatic expression that means to face a difficult or dangerous situation directly and with courage.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"utme","subject":"english","subjectLabel":"English Language","grade":"Unsorted"},{"id":"eZaECd0SIu8GRKOhFmW4","type":"objective","question":"Choose the option that has the correct stress pattern for the word: **photography**.","options":["PHO-to-gra-phy","pho-TOG-ra-phy","pho-to-GRA-phy","pho-to-gra-PHY"],"answerIndex":1,"answer":null,"explanation":"The word 'photography' is pronounced /fəˈtɒɡ.rə.fi/ with the primary stress on the second syllable.,Therefore, 'pho-TOG-ra-phy' is the correct stress pattern.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"utme","subject":"english","subjectLabel":"English Language","grade":"Unsorted"},{"id":"huCyYyhBDVxmy2d4JpxU","type":"objective","question":"The board of directors recommended that the project manager _______ with immediate effect.","options":["resigns","should resign","resign","resigned"],"answerIndex":2,"answer":null,"explanation":"The verb 'recommended' introduces a subjunctive clause.,The subjunctive mood requires the base form of the verb ('resign'), regardless of the subject's person or number.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"utme","subject":"english","subjectLabel":"English Language","grade":"Unsorted"},{"id":"kdub93bZ1SlhIErkpVsg","type":"objective","question":"Choose the option opposite in meaning to the bolded word:\\n\\nUnlike his twin brother who is extremely **gregarious**, Chidi prefers a quiet, solitary life.","options":["sociable","introverted","friendly","boisterous"],"answerIndex":1,"answer":null,"explanation":"'Gregarious' means fond of company and highly sociable.,The opposite of a sociable person is someone who is 'introverted'.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"utme","subject":"english","subjectLabel":"English Language","grade":"Unsorted"},{"id":"lN2NAKRKZ2vmTC20KS3a","type":"objective","question":"Choose the option that has the same vowel sound as the one represented by the underlined letter(s) in the word: f<u>oo</u>t.","options":["boot","could","blood","route"],"answerIndex":1,"answer":null,"explanation":"The word 'foot' contains the short vowel sound /ʊ/.,'Could' also contains the short /ʊ/ sound.,'Boot' and 'route' contain the long /uː/ sound, while 'blood' contains the /ʌ/ sound.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"utme","subject":"english","subjectLabel":"English Language","grade":"Unsorted"},{"id":"lsKxbH9jyCZkBW00YBjG","type":"objective","question":"Choose the option nearest in meaning to the bolded word:\\n\\nThe manager's **vituperative** remarks during the meeting left the employees demoralized.","options":["conciliatory","abusive","encouraging","ambiguous"],"answerIndex":1,"answer":null,"explanation":"'Vituperative' means harsh, bitter, and abusive.,Therefore, 'abusive' is the closest synonym.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"utme","subject":"english","subjectLabel":"English Language","grade":"Unsorted"}];
